import matplotlib.pyplot as plt
from matplotlib import rcParams

# WITH EXAMPLE TRAVERSAL

# ===== GLOBAL STYLE (matches your other figure) =====
fsize = 16
rcParams.update({
    'font.family': 'Times New Roman',
    'font.size': fsize,
    'axes.titlesize': fsize,
    'axes.labelsize': fsize,
    'xtick.labelsize': fsize,
    'ytick.labelsize': fsize,
    'legend.fontsize': fsize,
    'lines.linewidth': 1
})

# ===== COLOR SCHEME =====
# MAIN_BLUE       = '#4A6E8A'
# SECONDARY_BLUE  = '#A4B8C9'
# HIGHLIGHT_COLOR = '#2C3E50'
# GRAY_DARK       = '#5A5A5A'
# BLACK           = '#000000'
# WHITE           = '#FFFFFF'

MAIN_BLUE       = '#4A6E8A'
SECONDARY_BLUE  = '#A4B8C9'
HIGHLIGHT_COLOR = '#2C3E50'
GRAY_DARK       = '#5A5A5A'
BLACK           = '#000000'
WHITE           = '#FFFFFF'

# ===== FIXED LEVELS (perfectly even vertically) =====
y_root  = 0.95   # depth 0
y_lvl1  = 0.75   # depth 1
y_lvl2  = 0.55   # depth 2
y_leaf  = 0.35   # leaves

#fig, ax = plt.subplots(figsize=(7.2, 4.2))
fig, ax = plt.subplots(figsize=(10, 6))
ax.set_xlim(0.0, 1.0)
ax.set_ylim(0.25, 1.02)
ax.axis("off")

# ---------- Node / leaf coordinates ----------
nodes = {
    "root": (0.50, y_root),   # â„“1 < â„“2
    "n1L":  (0.25, y_lvl1),   # â„“2 < â„“3
    "n1R":  (0.75, y_lvl1),   # â„“1 < â„“3
    "n2L":  (0.25, y_lvl2),   # â„“1 < â„“3
    "n2R":  (0.75, y_lvl2),   # â„“2 < â„“3
}

leaves = {
    "L123": (0.15, y_leaf),
    "L132": (0.25, y_leaf),
    "L312": (0.35, y_leaf),
    "L213": (0.65, y_leaf),
    "L231": (0.75, y_leaf),
    "L321": (0.85, y_leaf),
}

leaf_labels = {
    "L123": r"$\sigma = 1\,2\,3$",
    "L132": r"$\sigma = 1\,3\,2$",
    "L312": r"$\sigma = 3\,1\,2$",
    "L213": r"$\sigma = 2\,1\,3$",
    "L231": r"$\sigma = 2\,3\,1$",
    "L321": r"$\sigma = 3\,2\,1$" + "\n" + r"sort output values $= [2, 4, 5]$",
}

# ---------- Edge list (no manual offsets; weâ€™ll compute them) ----------
edges = [
    ("root", "n1L",  "YES"),
    ("root", "n1R",  "NO"),
    ("n1L",  "L123", "YES"),
    ("n1L",  "n2L",  "NO"),
    ("n2L",  "L132", "YES"),
    ("n2L",  "L312", "NO"),
    ("n1R",  "L213", "YES"),
    ("n1R",  "n2R",  "NO"),
    ("n2R",  "L231", "YES"),
    ("n2R",  "L321", "NO"),
]

def get_xy(name):
    return nodes[name] if name in nodes else leaves[name]

# ---------- Draw edges + YES/NO labels slightly off the lines ----------
for parent, child, label in edges:
    x0, y0 = get_xy(parent)
    x1, y1 = get_xy(child)

    # edge
    if parent == "root" and child == "n1R":
        ax.plot([x0, x1], [y0, y1],
            color=BLACK, linewidth=5)
    elif parent == "n1R" and child == "n2R":
        ax.plot([x0, x1], [y0, y1],
            color=BLACK, linewidth=5)
    elif parent == "n2R" and child == "L321":
        ax.plot([x0, x1], [y0, y1],
            color=BLACK, linewidth=5)
    else:
        ax.plot([x0, x1], [y0, y1],
                color=GRAY_DARK, linewidth=1.5)

    # midpoint
    xm = 0.5 * (x0 + x1)
    ym = 0.5 * (y0 + y1)

    # small perpendicular offset so text is not on top of the line
    vx, vy = (x1 - x0), (y1 - y0)
    # normal vector (vy, -vx)
    norm_len = (vx**2 + vy**2) ** 0.5
    if norm_len == 0:
        nx, ny = 0.0, 0.0
    else:
        nx, ny = vy / norm_len, -vx / norm_len

    # move YES and NO to opposite sides of the edge
    side = 1.0 if label == "YES" else -1.0
    offset = 0.03  # magnitude of offset
    lx = xm + side * offset * nx
    ly = ym + side * offset * ny

    ax.text(lx, ly, label,
            ha="center", va="center",
            color=BLACK, fontsize=fsize, fontweight="bold")

# ---------- Draw nodes ----------
for x, y in nodes.values():
    ax.scatter(x, y, s=130,
               facecolor=WHITE,
               edgecolor=HIGHLIGHT_COLOR,
               linewidth=1.5,
               zorder=3)

for x, y in leaves.values():
    ax.scatter(x, y, s=130,
               facecolor=SECONDARY_BLUE,
               edgecolor=HIGHLIGHT_COLOR,
               linewidth=1.0,
               zorder=3)

# ---------- Labels on nodes ----------
# root stays exactly where it was
x_root, y_root_plot = nodes["root"]
ax.text(x_root, y_root_plot + .01, r"$\ell_1 < \ell_2$",
        ha="center", va="bottom",
        color=BLACK, fontsize=fsize)

# level 1: shift both labels toward the center
x, y = nodes["n1L"]
ax.text(x + 0.03, y, r"$\ell_2 < \ell_3$",
        ha="left", va="center",
        color=BLACK, fontsize=fsize)

x, y = nodes["n1R"]
ax.text(x + .03, y, r"$\ell_1 < \ell_3$",
        ha="left", va="center",
        color=BLACK, fontsize=fsize)

# level 2: â„“1 < â„“3 toward center; â„“2 < â„“3 pushed outward/right
x, y = nodes["n2L"]
ax.text(x + 0.03, y, r"$\ell_1 < \ell_3$",
        ha="left", va="center",
        color=BLACK, fontsize=fsize)

x, y = nodes["n2R"]
ax.text(x + 0.03, y, r"$\ell_2 < \ell_3$",
        ha="left", va="center",
        color=BLACK, fontsize=fsize)

# ---------- Leaf labels ----------
for name, label in leaf_labels.items():
    x, y = leaves[name]
    leaf_fontsize = 15 if name == "L321" else 14
    ax.text(x, y - 0.03, label,
            ha="center", va="top",
            color=BLACK, fontsize=leaf_fontsize)

# ---------- Annotations: root arrow & height ----------
# ax.annotate(
#     "root",
#     xy=nodes["root"],
#     xytext=(0.68, 0.97),
#     fontsize=12,
