#                     linewidth=1.4),
# )

ax.plot([0.95, 0.95], [y_leaf, y_root],
        color=HIGHLIGHT_COLOR, linewidth=2)
ax.text(0.97, 0.5 * (y_root + y_leaf),
        r"height = 3",
        rotation=90,
        va="center", ha="center",
        color=BLACK, fontsize=17)

ax.set_title(r"sort input values $L = [\ell_1 = 5,\ell_2 = 4,\ell_3 = 2]$",
             color=BLACK, fontsize=17)

plt.tight_layout()
plt.savefig("decision_tree_l_sort_tweaked.png", dpi=300, bbox_inches="tight")
plt.savefig("decision_tree_l_sort_tweaked.pdf", dpi=300, bbox_inches="tight")
plt.savefig("decision_tree_l_sort_tweaked.eps", dpi=300, bbox_inches="tight")
