# #### geometric perspective and the permutohedron

# %%
import numpy as np
import matplotlib.pyplot as plt
from matplotlib import rcParams

fsize = 18

# ===== GLOBAL STYLE (match decision_tree_bubble_style) =====
rcParams.update({
    'font.family': 'Times New Roman',
    'font.size': fsize,
    'axes.titlesize': fsize,
    'axes.labelsize': fsize,
    'xtick.labelsize': fsize,
    'ytick.labelsize': fsize,
    'legend.fontsize': fsize,
    'lines.linewidth': 1
})

# ===== COLOR SCHEME (same as tree figure) =====
BLACK           = '#000000'
MAIN_BLUE       = BLACK
SECONDARY_BLUE  = '#A4B8C9'
HIGHLIGHT_COLOR = BLACK
GRAY_DARK       = '#5A5A5A'
WHITE           = '#FFFFFF'

# ===== SINGLE FIGURE: Diagram 4 â€“ Walk on the S3 permutohedron =====
fig, ax4 = plt.subplots(figsize=(6, 6))

# Regular hexagon for the six permutations of S3
angles = np.linspace(0, 2 * np.pi, 6, endpoint=False)
hx = np.cos(angles)
hy = np.sin(angles)

# Order the permutations around the hexagon
perm_labels = ['123', '132', '312', '321', '231', '213']
perm_to_idx = {p: i for i, p in enumerate(perm_labels)}

# Pretty TeX labels
perm_tex = {
    '123': "$v_s$\n$(1,2,3)$",
    '132': r"$(1,3,2)$",
    '312': r"$(3,1,2)$",
    '321': "$x_0$\n$(3,2,1)$",
    '231': r"$(2,3,1)$",
    '213': r"$(2,1,3)$",
}

# ----- Draw hexagon edges (all permutations and adjacency) -----
for i in range(6):
    j = (i + 1) % 6
    ax4.plot(
        [hx[i], hx[j]],
        [hy[i], hy[j]],
        color=GRAY_DARK,
        linewidth=1.5,
        zorder=1
    )

# ----- Draw vertices -----
ax4.scatter(
    hx, hy,
    s=80,
    facecolor=SECONDARY_BLUE,
    edgecolor=HIGHLIGHT_COLOR,
    linewidth=1.0,
    zorder=3
)

# ----- Permutation labels (with manual tweaks for 321 and 123) -----
for i, p in enumerate(perm_labels):
    x = 1.15 * hx[i]
    y = 1.15 * hy[i]
    ha = "center"

    if p == '321':
        x = -1.32

    if p == '123':
        x = 1.32

    if p == '231':
        y -= 0.05

    if p == '213':
        y -= 0.05

    ax4.text(
        x,
        y,
        perm_tex[p],
        ha=ha,
        va="center",
        color=BLACK,
        fontsize=fsize
    )

# ----- Highlighted path: 321 â†’ 231 â†’ 213 â†’ 123 -----
path_perm = ['321', '231', '213', '123']
constraints_perm = [
    r"$x_1>x_2$",
    r"$x_2>x_3$",
    r"$x_1>x_2$",
]

for i in range(len(path_perm) - 1):
    a = perm_to_idx[path_perm[i]]
    b = perm_to_idx[path_perm[i + 1]]

    # thick highlighted edge
    ax4.plot(
        [hx[a], hx[b]],
        [hy[a], hy[b]],
        color=HIGHLIGHT_COLOR,
        linewidth=3.5,
        zorder=2
    )

    # constraint label near midpoint, nudged outward a bit
    xm = 0.5 * (hx[a] + hx[b])
    ym = 0.5 * (hy[a] + hy[b])

    # small radial push away from origin so labels don't sit on edges
    r = (xm**2 + ym**2) ** 0.9
    if r != 0:
        xm_off = xm * 1.1 / r
        ym_off = ym * 1.1 / r
    else:
        xm_off, ym_off = xm, ym

    # Move the bottom constraint Â¬(â„“2 < â„“3) slightly upward
    if constraints_perm[i] == r"$x_2>x_3$":
        ym_off -= 0.05
        xm_off -= .02

    ax4.text(
        xm_off,
        ym_off,
        constraints_perm[i],
        ha="center",
        va="center",
        color=MAIN_BLUE,
        fontsize=fsize
    )

ax4.set_aspect('equal', 'box')
ax4.set_xlim(-1.75, 1.75)
ax4.set_ylim(-1.55, 1.55)
ax4.axis("off")

# ax4.set_title(
#     r"sort input, $L =[\ell_1 = 5,\ell_2 = 4,\ell_3 = 2]$, output = $[2, 4, 5]$",
#     color=HIGHLIGHT_COLOR,
#     fontsize=fsize
# )

plt.tight_layout()
plt.savefig("permutohedron_bubble_style.png", dpi=300, bbox_inches="tight")
plt.savefig("permutohedron_bubble_style.pdf", dpi=300, bbox_inches="tight")
plt.savefig("permutohedron_bubble_style.eps", dpi=300, bbox_inches="tight")
plt.show()

from PyPDF2 import PdfReader, PdfWriter

input_pdf  = "permutohedron_bubble_style.pdf"
