import matplotlib.pyplot as plt
from itertools import permutations
import numpy as np
from mpl_toolkits.mplot3d import proj3d
from matplotlib import rcParams
from matplotlib.patches import FancyArrowPatch

fsize = 18

rcParams.update({
    'font.family': 'Times New Roman',
    'font.size': 14,
    'axes.titlesize': 14,
    'axes.labelsize': 14,
    'xtick.labelsize': 14,
    'ytick.labelsize': 14,
    'legend.fontsize': 14,
    'lines.linewidth': 1
})

# ===== COLOR SCHEME =====
MAIN_BLUE = '#4A6E8A'
SECONDARY_BLUE = '#A4B8C9'
HIGHLIGHT_COLOR = '#2C3E50'
GRAY_LIGHT = '#D3D3D3'
GRAY_MEDIUM = '#A9A9A9'
GRAY_DARK = '#5A5A5A'
BLACK = '#000000'
WHITE = '#FFFFFF'

# ===== FONT SIZE =====
MAIN_FONT_SIZE = 22
TITLE_FONT_SIZE = MAIN_FONT_SIZE + 2
SMALL_FONT_SIZE = MAIN_FONT_SIZE - 4

# --- Helper: 3D arrow class ---
class Arrow3D(FancyArrowPatch):
    def __init__(self, xs, ys, zs, *args, **kwargs):
        super().__init__((0, 0), (0, 0), *args, **kwargs)
        self._verts3d = xs, ys, zs

    def draw(self, renderer):
        xs3d, ys3d, zs3d = self._verts3d
        xs, ys, zs = proj3d.proj_transform(xs3d, ys3d, zs3d, self.axes.M)
        self.set_positions((xs[0], ys[0]), (xs[1], ys[1]))
        super().draw(renderer)

    def do_3d_projection(self, renderer=None):
        xs3d, ys3d, zs3d = self._verts3d
        xs, ys, zs = proj3d.proj_transform(xs3d, ys3d, zs3d, self.axes.M)
        self.set_positions((xs[0], ys[0]), (xs[1], ys[1]))
        return np.min(zs)

# Generate all permutations of (1, 2, 3)
perm = list(permutations([1, 2, 3]))
vertices = [list(p) for p in perm]
perm_to_idx = {perm[i]: i for i in range(len(perm))}

# Connect vertices that differ by one adjacent transposition
edges = []
for i, p1 in enumerate(perm):
    for j, p2 in enumerate(perm):
        diff_count = sum(1 for a, b in zip(p1, p2) if a != b)
        if diff_count == 2:
            for k in range(len(p1) - 1):
                if {p1[k], p1[k+1]} == {p2[k], p2[k+1]}:
                    edges.append((i, j))
                    break

# === FIGURE: Initial State with Emphasized Line ===

fig = plt.figure(figsize=(7, 7))
ax = fig.add_subplot(111, projection='3d')

# --- Initial state: vertices and edges (UPDATED VERTEX STYLE ONLY) ---
for i, v in enumerate(vertices):
    ax.scatter(
        v[0], v[1], v[2],
        s=122,
        facecolor=SECONDARY_BLUE,
        edgecolor=BLACK,
        linewidth=1.0
    )

    #print(type(v[0]))
    #print(v)
    if v[0] == 3 and v[1] == 1 and v[2] == 2:
        ax.text(
            v[0] - .5,
            v[1] - .2,
            v[2],
            str(tuple(v)),
            fontsize=MAIN_FONT_SIZE
        )
    else:
        ax.text(
            v[0] + .1,
            v[1],
            v[2] + .05,
            str(tuple(v)),
            fontsize=MAIN_FONT_SIZE
        )

# base edges
for i, j in edges:
    ax.plot(
        [vertices[i][0], vertices[j][0]],
        [vertices[i][1], vertices[j][1]],
        [vertices[i][2], vertices[j][2]],
        color=GRAY_MEDIUM,
        alpha=0.7,
        linewidth=3
    )

# --- Highlight the edge traversal  (3,2,1) â†’ (2,3,1) â†’ (2,1,3) â†’ (1,2,3) ---
path_perm = [(3, 2, 1), (2, 3, 1), (2, 1, 3), (1, 2, 3)]
edge_labels = [
    r"$x_1>x_2$",
    r"$x_2>x_3$",
    r"$x_1>x_2$",
]

# offsets you can tune
dx_top = -1      # move top Â¬(l1<l2) left (currently unused but kept)
dz_bottom = 0.25 # move bottom Â¬(l1<l2) up (currently unused but kept)

for k in range(len(path_perm) - 1):
    i = perm_to_idx[path_perm[k]]
    j = perm_to_idx[path_perm[k + 1]]
    v_i = np.array(vertices[i], dtype=float)
    v_j = np.array(vertices[j], dtype=float)

    # highlighted edge
    ax.plot(
        [v_i[0], v_j[0]],
        [v_i[1], v_j[1]],
        [v_i[2], v_j[2]],
        color=HIGHLIGHT_COLOR,
        linewidth=5.0,
    )

    # --- Edge label (same as 2D hex figure) ---
    mid = 0.5 * (v_i + v_j)
    center = np.array([2.0, 2.0, 2.0])
    direction = mid - center
    # small radial push so text is off the edge
    mid_off = mid + 0.18 * direction

    # k = 0 : bottom Â¬(l1<l2)   â†’ move up in z
    if k == 0:
        mid_off[0] += -.14  # horizontal
        mid_off[2] += .25  # vertical

    if k == 1:
        mid_off[0] += -.7
        mid_off[2] += -.55

    # k = 2 : top Â¬(l1<l2)      â†’ move left in x
    if k == 2:
        mid_off[0] += -.7
        mid_off[2] += -.5

    ax.text(
        mid_off[0],
        mid_off[1],
        mid_off[2],
        edge_labels[k],
        color=BLACK,
        fontsize=MAIN_FONT_SIZE
    )

