import numpy as np
import matplotlib.pyplot as plt
from mpl_toolkits.mplot3d import Axes3D
from matplotlib import rcParams

# --- Start & End node color (slightly darker, navy-leaning) ---
DARK_NODE = "#375A7F"     # dark blue, close to navy

rcParams.update({
    'font.family': 'Times New Roman',
    'font.size': 18,
    'axes.titlesize': 18,
    'axes.labelsize': 18,
    'xtick.labelsize': 18,
    'ytick.labelsize': 18,
    'legend.fontsize': 18,
    'lines.linewidth': 1
})


# Parameters
n = 3
R0 = 8.0
r0 = np.sqrt(R0)
V0 = 0.5 * r0**2
eps = 0.01
T_eps = np.log(r0 / eps)
t_max = np.ceil(T_eps)
nlogn = n * np.log(n)

def r_flow(t, r0):
    t = np.asarray(t)
    return r0 * np.exp(-t)

def V_of_r(r):
    r = np.asarray(r)
    return 0.5 * r**2

# Data generation
t_dense = np.linspace(0.0, T_eps, 300)
r_dense = r_flow(t_dense, r0)
V_dense = V_of_r(r_dense)

k_steps = np.arange(0, int(t_max) + 1)
r_steps = r_flow(k_steps, r0)
V_steps = V_of_r(r_steps)

r_vals = np.linspace(0.0, r0, 100)
t_vals = np.linspace(0.0, t_max, 100)
R_grid, T_grid = np.meshgrid(r_vals, t_vals)
V_grid = V_of_r(R_grid)

# Plotting - INCREASED figure width to prevent cutoff
fig = plt.figure(figsize=(9, 9))  # Changed from (7, 7) to (9, 7)
ax = fig.add_subplot(111, projection='3d')

ax.plot_surface(R_grid, T_grid, V_grid, alpha=0.3)
ax.plot(r_dense, t_dense, V_dense, linewidth=3, alpha=0.8, color="black")

# --- UPDATED NODE STYLE (matches permutohedron nodes) ---
ax.scatter(
    r_steps[:-1],
    k_steps[:-1],
    V_steps[:-1],
    s=122,
    facecolor="navy",   # SECONDARY_BLUE
    edgecolor="#000000",   # BLACK
    linewidth=1.5
)

# Markers
start_t = 0.0
start_r = r0
start_V = V0
stop_t = T_eps
stop_r = r_flow(stop_t, r0)
stop_V = V_of_r(stop_r)

ax.scatter(
    [start_r],
    [start_t],
    [start_V],
    s=122,
    facecolor="black",
    edgecolor="#000000",
    linewidth=1.5
)
ax.scatter(
    [stop_r],
    [stop_t],
    [stop_V],
    s=122,
    facecolor="black",
    edgecolor="#000000",
    linewidth=1.5
)

ax.text(
    start_r - .12,
    start_t,
    start_V - .25,
    rf"($r={start_r:.2f},$" + "\n" + r"    $t=0$)",
    ha="left",
    va="top",
    fontsize=25
)
ax.text(
    stop_r,
    stop_t,
    stop_V + 0.2,
    r"$(r \approx \varepsilon, t = T_\varepsilon)$",
    ha="center",
    va="bottom",
    fontsize=25
)

# Labels
ax.set_xlabel(r"$r=\|x - v_s\|_2$", fontsize=25, labelpad = 10)
ax.set_ylabel(r"$t$", fontsize=25)
# Remove default z-label
ax.set_zlabel("")

# Compute the top of the z-axis in 3D coords
z_top = ax.get_zlim()[1]
x0, y0 = ax.get_xlim()[0], ax.get_ylim()[0]

# Add label above the z axis
ax.text(
    x0 + 4.7,                     # anchor x: left edge of plot
    y0,                           # anchor y: bottom edge of plot
    z_top + 0.1 * (z_top) + 3.2,  # slightly above top of z-axis
    r"$V(r(t))$",
    ha="center",
    va="bottom",
    fontsize=25
)

ax.set_yticks([0, t_max])
ax.set_yticklabels([r"0", r"$T_\varepsilon$"])

# Saving
plt.savefig('final_gradient_path.png', dpi=300, bbox_inches='tight')
plt.savefig('final_gradient_path.pdf', dpi=300, bbox_inches='tight')
plt.savefig('final_gradient_path.eps', dpi=300, bbox_inches='tight')

