ax.yaxis._axinfo["grid"]['color'] = (0.85, 0.85, 0.85, 0.45)
ax.zaxis._axinfo["grid"]['color'] = (0.85, 0.85, 0.85, 0.45)

ax.xaxis.set_pane_color((1, 1, 1, 0.0))
ax.yaxis.set_pane_color((1, 1, 1, 0.0))
ax.zaxis.set_pane_color((1, 1, 1, 0.0))

ax.view_init(elev=18, azim=135)

plt.tight_layout()

# === SAVE =====================================================================

filename_base = 'tangent_cone_projection_vertex_edge_labels_separate'
plt.savefig(f'{filename_base}.png', dpi=300, bbox_inches='tight')
plt.savefig(f'{filename_base}.pdf', dpi=300, bbox_inches='tight')
plt.savefig(f'{filename_base}.eps', dpi=300, bbox_inches='tight')

input_pdf  = f"{filename_base}.pdf"
output_pdf = f"{filename_base}_scaled.pdf"

target_width_inch  = 5.0
target_height_inch = 5.0
target_w_pt = target_width_inch  * 72
target_h_pt = target_height_inch * 72

try:
    reader = PdfReader(input_pdf)
    writer = PdfWriter()
    page   = reader.pages[0]

    orig_w_pt = float(page.mediabox.width)
    orig_h_pt = float(page.mediabox.height)

    scale_w = target_w_pt / orig_w_pt
    scale_h = target_w_pt / orig_h_pt
    scale   = min(scale_w, scale_h)

    page.scale_by(scale)
    writer.add_page(page)
    with open(output_pdf, "wb") as f:
        writer.write(f)
    print(f"Saved '{output_pdf}' at ~{target_width_inch}\"Ã—{target_height_inch}\".")
except Exception as e:
    print("Skipped PDF scaling:", e)


